#include <iostream>

class Point {
private:
    int x;
    int y;

public:
    Point() {
        this->x = 0;
        this->y = 0;
    }

    Point(int x_val, int y_val) {
        this->x = x_val;
        this->y = y_val;
    }

    int getX() const {
        return x;
    }

    int getY() const {
        return y;
    }
};

int main() {
    Point p1;
    std::cout << p1.getX() << " " << p1.getY() << std::endl;

    Point p2(5, 10);
    std::cout << p2.getX() << " " << p2.getY() << std::endl;

    Point p3(-3, 7);
    std::cout << p3.getX() << " " << p3.getY() << std::endl;

    return 0;
}
